    def update_build_config(self, build_config, field_value, field_name=None):
        dynamic_fields = [
            "column_name",
            "filter_value",
            "filter_operator",
            "ascending",
            "new_column_name",
            "new_column_value",
            "columns_to_select",
            "num_rows",
            "replace_value",
            "replacement_value",
        ]
        for field in dynamic_fields:
            build_config[field]["show"] = False

        if field_name == "operation":
            # Handle SortableListInput format
            if isinstance(field_value, list):
                operation_name = field_value[0].get("name", "") if field_value else ""
            else:
                operation_name = field_value or ""

            # If no operation selected, all dynamic fields stay hidden (already set to False above)
            if not operation_name:
                return build_config

            if operation_name == "Filter":
                build_config["column_name"]["show"] = True
                build_config["filter_value"]["show"] = True
                build_config["filter_operator"]["show"] = True
            elif operation_name == "Sort":
                build_config["column_name"]["show"] = True
                build_config["ascending"]["show"] = True
            elif operation_name == "Drop Column":
                build_config["column_name"]["show"] = True
            elif operation_name == "Rename Column":
                build_config["column_name"]["show"] = True
                build_config["new_column_name"]["show"] = True
            elif operation_name == "Add Column":
                build_config["new_column_name"]["show"] = True
                build_config["new_column_value"]["show"] = True
            elif operation_name == "Select Columns":
                build_config["columns_to_select"]["show"] = True
            elif operation_name in {"Head", "Tail"}:
                build_config["num_rows"]["show"] = True
            elif operation_name == "Replace Value":
                build_config["column_name"]["show"] = True
                build_config["replace_value"]["show"] = True
                build_config["replacement_value"]["show"] = True
            elif operation_name == "Drop Duplicates":
                build_config["column_name"]["show"] = True

        return build_config

    def perform_operation(self) -> DataFrame:
        df_copy = self.df.copy()

        # Handle SortableListInput format for operation
        operation_input = getattr(self, "operation", [])
        if isinstance(operation_input, list) and len(operation_input) > 0:
            op = operation_input[0].get("name", "")
        else:
            op = ""

        # If no operation selected, return original DataFrame
        if not op:
            return df_copy

        if op == "Filter":
            return self.filter_rows_by_value(df_copy)
        if op == "Sort":
            return self.sort_by_column(df_copy)
        if op == "Drop Column":
            return self.drop_column(df_copy)
        if op == "Rename Column":
            return self.rename_column(df_copy)
        if op == "Add Column":
            return self.add_column(df_copy)
        if op == "Select Columns":
            return self.select_columns(df_copy)
        if op == "Head":
            return self.head(df_copy)
        if op == "Tail":
            return self.tail(df_copy)
        if op == "Replace Value":
            return self.replace_values(df_copy)
        if op == "Drop Duplicates":
            return self.drop_duplicates(df_copy)
        msg = f"Unsupported operation: {op}"
        logger.error(msg)
        raise ValueError(msg)

    def filter_rows_by_value(self, df: DataFrame) -> DataFrame:
        column = df[self.column_name]
        filter_value = self.filter_value

        # Handle regular DropdownInput format (just a string value)
        operator = getattr(self, "filter_operator", "equals")  # Default to equals for backward compatibility

        if operator == "equals":
            mask = column == filter_value
        elif operator == "not equals":
            mask = column != filter_value
        elif operator == "contains":
            mask = column.astype(str).str.contains(str(filter_value), na=False)
        elif operator == "starts with":
            mask = column.astype(str).str.startswith(str(filter_value), na=False)
        elif operator == "ends with":
            mask = column.astype(str).str.endswith(str(filter_value), na=False)
        elif operator == "greater than":
            try:
                # Try to convert filter_value to numeric for comparison
                numeric_value = pd.to_numeric(filter_value)
                mask = column > numeric_value
            except (ValueError, TypeError):
                # If conversion fails, compare as strings
                mask = column.astype(str) > str(filter_value)
        elif operator == "less than":
            try:
                # Try to convert filter_value to numeric for comparison
                numeric_value = pd.to_numeric(filter_value)
                mask = column < numeric_value
            except (ValueError, TypeError):
                # If conversion fails, compare as strings
                mask = column.astype(str) < str(filter_value)
        else:
            mask = column == filter_value  # Fallback to equals

        return DataFrame(df[mask])

    def sort_by_column(self, df: DataFrame) -> DataFrame:
        return DataFrame(df.sort_values(by=self.column_name, ascending=self.ascending))

    def drop_column(self, df: DataFrame) -> DataFrame:
        return DataFrame(df.drop(columns=[self.column_name]))

    def rename_column(self, df: DataFrame) -> DataFrame:
        return DataFrame(df.rename(columns={self.column_name: self.new_column_name}))

    def add_column(self, df: DataFrame) -> DataFrame:
        df[self.new_column_name] = [self.new_column_value] * len(df)
        return DataFrame(df)

    def select_columns(self, df: DataFrame) -> DataFrame:
        columns = [col.strip() for col in self.columns_to_select]
        return DataFrame(df[columns])

    def head(self, df: DataFrame) -> DataFrame:
        return DataFrame(df.head(self.num_rows))

    def tail(self, df: DataFrame) -> DataFrame:
        return DataFrame(df.tail(self.num_rows))

    def replace_values(self, df: DataFrame) -> DataFrame:
        df[self.column_name] = df[self.column_name].replace(self.replace_value, self.replacement_value)
        return DataFrame(df)

    def drop_duplicates(self, df: DataFrame) -> DataFrame:
        return DataFrame(df.drop_duplicates(subset=self.column_name))

import json
from json import JSONDecodeError
from typing import Any, List, Union

from jsonpath_ng import parse
from jsonpath_ng.exceptions import JsonPathParserError
from langflow.custom import Component
from langflow.io import FileInput, MultilineInput, Output, DataInput, TabInput
from langflow.schema import Data
from langflow.schema.dotdict import dotdict
from platformdirs import user_cache_dir


class JSONPathComponent(Component):
    display_name = "JSONPath"
    description = (
        "Извлекает данные из JSON по выражениям JSONPath. "
        "Поддерживает несколько путей и вложенные структуры."
    )
    icon = "AIGateway"
    name = "JSONPath"

    inputs = [
        TabInput(
            name="mode",
            display_name="Источник JSON",
            options=["Строка", "Объект", "Файл"],
            value="Строка",
            info="Выберите, откуда брать JSON.",
            real_time_refresh=True,
        ),
        MultilineInput(
            name="input_json",
            display_name="JSON строка",
            info="Строка JSON. Используется в режиме \"Строка\".",
            show=True,
        ),
        DataInput(
            name="input_json_object",
            display_name="JSON объект",
            info="Объект JSON из предыдущего компонента. Используется в режиме \"Объект\".",
            show=False,
        ),
        FileInput(
            name="input_json_file",
            display_name="JSON файл",
            fileTypes=["json", "txt"],
            info="Файл с JSON. Используется в режиме \"Файл\".",
            show=False,
        ),
        MultilineInput(
            name="json_paths",
            display_name="JSONPath-выражения",
            info="Список выражений JSONPath (например: $.user.name, $.items[*].id).",
            list=True,
        ),
    ]

    outputs = [
        Output(
            display_name="Результат выборки",
            name="preparing_data",
            method="preparing_data",
        ),
    ]

    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.user_cache_dir = user_cache_dir("langflow")
        self._temp_files_to_delete = {}
        self.fields_to_clear = ["input_json_file"]

    def update_build_config(self, build_config: dotdict, field_value: Any, field_name: str | None = None):
        if field_name == "mode":
            is_text = field_value == "Строка"
            is_object = field_value == "Объект"
            is_file = field_value == "Файл"

            build_config["input_json"]["show"] = is_text
            build_config["input_json"]["required"] = is_text

            build_config["input_json_object"]["show"] = is_object
            build_config["input_json_object"]["required"] = is_object

            build_config["input_json_file"]["show"] = is_file
            build_config["input_json_file"]["required"] = is_file

        return build_config

    def _get_json_input(self) -> Any:
        mode = getattr(self, "mode", "Строка")

        if mode == "Объект":
            return self.input_json_object

        if mode == "Файл":
            if not self.input_json_file:
                return ""
            return self._read_json_file()

        return self.input_json

    def _read_json_file(self) -> str:
        with open(self.input_json_file, "r", encoding="utf-8") as file:
            return file.read()

    def _parse_json(self, json_str: str) -> Union[dict, list]:
        try:
            return json.loads(json_str)
        except JSONDecodeError as e:
            raise ValueError(f"Некорректный формат JSON: {str(e)}") from e

    def _ensure_json_data(self, value: Any) -> Any:
        if isinstance(value, (dict, list)):
            return value

        if isinstance(value, Data):
            return value.data

        if isinstance(value, str):
            s = value.strip()
            if s.startswith("{") or s.startswith("["):
                return self._parse_json(s)
            raise ValueError("Ожидается JSON-объект или массив, получена строка.")

        if hasattr(value, "to_dict"):
            return value.to_dict()

        raise ValueError(f"Неподдерживаемый тип входных данных: {type(value)}")

    def _get_paths_to_process(self) -> List[str]:
        if not self.json_paths or self.json_paths == [""]:
            raise ValueError("Не указаны JSONPath-выражения.")
        return self.json_paths

    async def preparing_data(self) -> List[Data]:
        try:
            raw_input = self._get_json_input()
            if raw_input is None or raw_input == "":
                raise ValueError("Входной JSON пуст.")

            json_data = self._ensure_json_data(raw_input)
            results: dict[str, Any] = {}

            for path in self._get_paths_to_process():
                p = (path or "").strip()
                if not p:
                    results[path] = "Некорректный путь: пустая строка."
                    continue

                try:
                    expr = parse(p)
                    matches = [m.value for m in expr.find(json_data)]

                    if not matches:
                        results[p] = "Совпадений не найдено."
                    elif len(matches) == 1:
                        results[p] = matches[0]
                    else:
                        results[p] = matches

                except JsonPathParserError as e:
                    results[p] = f"Ошибка в выражении JSONPath: {e}"

            return Data(data=results)

        except Exception as e:
            raise ValueError(f"Ошибка обработки JSON: {str(e)}") from e

        finally:
            self._cleanup_files()

import importlib

from langchain_experimental.utilities import PythonREPL

from langflow.custom.custom_component.component import Component
from langflow.io import CodeInput, Output, StrInput
from langflow.schema.data import Data


class PythonREPLComponent(Component):
    display_name = "Python Interpreter"
    description = "Run Python code with optional imports. Use print() to see the output."
    documentation: str = "https://docs.langflow.org/components-processing#python-interpreter"
    icon = "square-terminal"

    inputs = [
        StrInput(
            name="global_imports",
            display_name="Global Imports",
            info="A comma-separated list of modules to import globally, e.g. 'math,numpy,pandas'.",
            value="math,pandas",
            required=True,
        ),
        CodeInput(
            name="python_code",
            display_name="Python Code",
            info="The Python code to execute. Only modules specified in Global Imports can be used.",
            value="print('Hello, World!')",
            input_types=["Message"],
            tool_mode=True,
            required=True,
        ),
    ]

    outputs = [
        Output(
            display_name="Results",
            name="results",
            type_=Data,
            method="run_python_repl",
        ),
    ]

    def get_globals(self, global_imports: str | list[str]) -> dict:
        """Create a globals dictionary with only the specified allowed imports."""
        global_dict = {}

        try:
            if isinstance(global_imports, str):
                modules = [module.strip() for module in global_imports.split(",")]
            elif isinstance(global_imports, list):
                modules = global_imports
            else:
                msg = "global_imports must be either a string or a list"
                raise TypeError(msg)

            for module in modules:
                try:
                    imported_module = importlib.import_module(module)
                    global_dict[imported_module.__name__] = imported_module
                except ImportError as e:
                    msg = f"Could not import module {module}: {e!s}"
                    raise ImportError(msg) from e

        except Exception as e:
            self.log(f"Error in global imports: {e!s}")
            raise
        else:
            self.log(f"Successfully imported modules: {list(global_dict.keys())}")
            return global_dict

    def run_python_repl(self) -> Data:
        try:
            globals_ = self.get_globals(self.global_imports)
            python_repl = PythonREPL(_globals=globals_)
            result = python_repl.run(self.python_code)
            result = result.strip() if result else ""

            self.log("Code execution completed successfully")
            return Data(data={"result": result})

        except ImportError as e:
            error_message = f"Import Error: {e!s}"
            self.log(error_message)
            return Data(data={"error": error_message})

        except SyntaxError as e:
            error_message = f"Syntax Error: {e!s}"
            self.log(error_message)
            return Data(data={"error": error_message})

        except (NameError, TypeError, ValueError) as e:
            error_message = f"Error during execution: {e!s}"
            self.log(error_message)
            return Data(data={"error": error_message})

    def build(self):
        return self.run_python_repl

