        'request': 'Учитывая приведённый разговор выше, реши, корректно ли следующее сообщение от менеджера: '
        'Добрый день! Хочу предложить Вам наш продукт Новый СберПремьер!',
        'params': {'is_valid': '1', 'feedback': "Сообщение валидно"},
    },
    {
        'request': 'Учитывая приведённый разговор выше, реши, корректно ли следующее сообщение от менеджера: '
        'Привет!',
        'params': {
            'is_valid': '0',
            'feedback': 'Сообщение слишком неформальное и не соответствует стандартам общения банка.',
        },
    },
    {
        'request': 'Учитывая приведённый разговор выше, реши, корректно ли следующее сообщение от менеджера: '
        'Это набор финансовых и нефинансовых привилегий, о чем именно будет Вам интереснее узнать?',
        'params': {'is_valid': '1', 'feedback': "Сообщение валидно"},
    }
]
        """,
        ),
        BoolInput(
            name="multiple",
            display_name="Generate Multiple",
            info="Set to True if the model should generate a list of outputs instead of a single output.",
            value=False,
        ),
    ]

    outputs = [
        Output(name="structured_output", display_name="Structured Output", method="build_structured_output"),
    ]

    def build_structured_output(self) -> Data:
        if not hasattr(self.llm, "with_structured_output"):
            msg = "Language model does not support structured output."
            raise TypeError(msg)
        if not self.output_schema:
            msg = "Output schema cannot be empty"
            raise ValueError(msg)

        _output_model = build_model_from_schema(self.output_schema)
        if self.multiple:
            output_model = create_model(
                self.schema_name,
                objects=(list[_output_model], Field(description=self.schema_name)),  # type: ignore[valid-type]
            )
        else:
            output_model = _output_model
        output_model.__doc__ = f"Функция осуществляет проверку по списку объектов {self.schema_name}"
        if self.few_shot_examples:
            output_model.few_shot_examples = self.get_few_shot_examples()
        try:
            llm_with_structured_output = cast(LanguageModel, self.llm).with_structured_output(schema=output_model)  # type: ignore[valid-type, attr-defined]

        except NotImplementedError as exc:
            msg = f"{self.llm.__class__.__name__} does not support structured output."
            raise TypeError(msg) from exc
        config_dict = {
            "display_name": self.display_name,
            "get_project_name": self.get_project_name,
            "get_langchain_callbacks": self.get_langchain_callbacks,
        }
        output = get_chat_result(runnable=llm_with_structured_output, input_value=self.input_value, config=config_dict)
        if isinstance(output, BaseModel):
            output_dict = output.model_dump()
            if self.multiple:
                output_ = [Data(data=o_) for o_ in output_dict["objects"]]
            else:
                output_ = Data(data=output_dict)
        else:
            msg = f"Output should be a Pydantic BaseModel, got {type(output)} ({output})"
            raise TypeError(msg)
        return output_

    def get_few_shot_examples(self):
        function_code = f"""
def few_shot_examples():
    return {self.few_shot_examples}
        """
        func = staticmethod(get_function(function_code))
        return func

